import { useEffect, useState } from "react";
import { useLang } from "../hooks/useLang";

const LogoIcon = () => (
  <div
    style={{
      width: 38,
      height: 38,
      borderRadius: 11,
      background:
        "linear-gradient(135deg, var(--surface-2) 0%, var(--surface) 100%)",
      border: "1px solid var(--line-2)",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      position: "relative",
      overflow: "hidden",
      boxShadow:
        "0 4px 16px rgba(0,0,0,.4), inset 0 1px 0 rgba(255,255,255,.07)",
      flexShrink: 0,
    }}
  >
    <div
      style={{
        position: "absolute",
        inset: 0,
        background:
          "radial-gradient(circle at 30% 30%, rgba(94,141,255,.4) 0%, transparent 70%)",
      }}
    />
    <svg
      width="22"
      height="22"
      viewBox="0 0 22 22"
      fill="none"
      style={{ position: "relative", zIndex: 1 }}
    >
      <rect
        x="2"
        y="9"
        width="18"
        height="3"
        rx="1.5"
        fill="rgba(94,141,255,0.9)"
      />
      <rect
        x="5.5"
        y="12"
        width="2.5"
        height="7"
        rx="1.25"
        fill="rgba(255,255,255,0.6)"
      />
      <rect
        x="14"
        y="12"
        width="2.5"
        height="7"
        rx="1.25"
        fill="rgba(255,255,255,0.6)"
      />
      <circle cx="11" cy="4.5" r="2.5" fill="rgba(255,255,255,0.8)" />
    </svg>
  </div>
);

export default function Navbar() {
  const { isAr, toggle, t } = useLang();
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handler = () => setScrolled(window.scrollY > 30);
    window.addEventListener("scroll", handler, { passive: true });
    return () => window.removeEventListener("scroll", handler);
  }, []);

  const links = [
    { href: "#how", label: t("How It Works", "كيف يعمل") },
    { href: "#features", label: t("Features", "الميزات") },
    { href: "#pricing", label: t("Pricing", "الأسعار") },
    { href: "#faq", label: t("FAQ", "الأسئلة") },
  ];

  return (
    <nav
      style={{
        position: "fixed",
        top: 0,
        left: 0,
        right: 0,
        zIndex: 1000,
        padding: "0 32px",
        background: scrolled ? "rgba(8,7,6,.88)" : "transparent",
        backdropFilter: scrolled ? "blur(24px) saturate(180%)" : "none",
        borderBottom: scrolled
          ? "1px solid var(--line)"
          : "1px solid transparent",
        transition: "all 0.5s cubic-bezier(0.16,1,0.3,1)",
      }}
    >
      <div
        style={{
          maxWidth: 1200,
          margin: "0 auto",
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          height: 72,
        }}
      >
        <a
          href="/"
          style={{
            display: "flex",
            alignItems: "center",
            gap: 11,
            textDecoration: "none",
            cursor: "none",
          }}
        >
          <LogoIcon />
          <div>
            <div
              style={{
                fontFamily: "'Playfair Display', serif",
                fontSize: 20,
                fontWeight: 700,
                letterSpacing: "-0.02em",
                color: "var(--text-primary)",
              }}
            >
              Tawla
            </div>
            <div
              style={{
                fontFamily: "'Noto Sans Arabic', sans-serif",
                fontSize: 13,
                color: "var(--text-muted)",
                marginTop: -3,
              }}
            >
              طاولة
            </div>
          </div>
        </a>

        <ul
          style={{
            display: "flex",
            alignItems: "center",
            gap: 36,
            listStyle: "none",
            margin: 0,
            padding: 0,
          }}
        >
          {links.map((l) => (
            <li key={l.href}>
              <a
                href={l.href}
                style={{
                  color: "var(--text-secondary)",
                  fontSize: 14,
                  fontWeight: 500,
                  textDecoration: "none",
                  cursor: "none",
                  transition: "color 0.2s",
                }}
                onMouseEnter={(e) =>
                  (e.target.style.color = "var(--text-primary)")
                }
                onMouseLeave={(e) =>
                  (e.target.style.color = "var(--text-secondary)")
                }
              >
                {l.label}
              </a>
            </li>
          ))}
        </ul>

        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <button
            onClick={toggle}
            style={{
              background: "var(--surface-2)",
              border: "1px solid var(--line)",
              borderRadius: "var(--r-full)",
              padding: "6px 14px",
              fontSize: 12,
              fontWeight: 600,
              color: "var(--text-muted)",
              cursor: "none",
              transition: "all 0.2s",
              fontFamily: "'DM Sans', sans-serif",
            }}
            onMouseEnter={(e) => {
              e.target.style.color = "var(--text-primary)";
              e.target.style.borderColor = "var(--line-2)";
            }}
            onMouseLeave={(e) => {
              e.target.style.color = "var(--text-muted)";
              e.target.style.borderColor = "var(--line)";
            }}
          >
            {isAr ? "English" : "العربية"}
          </button>
          <a
            href="#demo"
            className="btn-gold"
            style={{ padding: "11px 24px", fontSize: 14 }}
          >
            {t("Book Demo →", "احجز عرضاً ←")}
          </a>
        </div>
      </div>
    </nav>
  );
}
